defmodule YourAppWeb.WebhookProxyController do
  use YourAppWeb, :controller

  @allowed_schemes ["http", "https"]
  @blocked_ips [
    # Loopback
    {127, 0, 0, 0}, {127, 0, 0, 0, 8},
    # Private networks
    {10, 0, 0, 0}, {10, 0, 0, 0, 8},
    {172, 16, 0, 0}, {172, 16, 0, 0, 12},
    {192, 168, 0, 0}, {192, 168, 0, 0, 16},
