  defp validate_and_fetch(url) do
    with {:ok, parsed_url} <- parse_url(url),
         :ok <- validate_scheme(parsed_url),
         :ok <- validate_hostname(parsed_url),
         {:ok, ip_addresses} <- resolve_hostname(parsed_url.host),
         :ok <- validate_ip_addresses(ip_addresses),
         {:ok, response} <- fetch_url(url) do
      {:ok, response}
    else
      {:error, reason} -> {:error, reason}
    end
  end

  defp parse_url(url) do
    case URI.parse(url) do
      %URI{scheme: nil} -> {:error, "Invalid URL: missing scheme"}
      %URI{host: nil} -> {:error, "Invalid URL: missing host"}
      parsed_url -> {:ok, parsed_url}
    end
  end

  defp validate_scheme(%URI{scheme: scheme}) do
    if scheme in @allowed_schemes do
      :ok
    else
      {:error, "Invalid scheme: only http and https are allowed"}
    end
  end

  defp validate_hostname(%URI{host: host}) do
    normalized_host = String.downcase(host)

    cond do
      normalized_host in @blocked_hostnames ->
        {:error, "Blocked hostname"}

      is_ip_address?(normalized_host) ->
        case parse_ip(normalized_host) do
